#include <stdio.h>
#include <string.h>
#define MAX 10000
#define MAX_LEN 20
#define MAX_DIGITS 10

int minWords(char *words[], int K, int digitMap[][15], int n, int digits[]) {
    int dp[n + 1];
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i] = -1;
        for (int j = 0; j < K; j++) {
            int len = strlen(words[j]);
            if (i >= len) {
                int match = 1;
                for (int k = 0; k < len; k++) {
                    int found = 0;
                    for (int l = 0; l < 15; l++) {
                        if (digitMap[digits[i - k - 1]][l] == words[j][len - k - 1]) {
                            found = 1;
                            break;
                        }
                    }
                    if (!found) {
                        match = 0;
                        break;
                    }
                }
                if (match && dp[i - len] != -1) {
                    if (dp[i] == -1 || dp[i - len] + 1 < dp[i]) {
                        dp[i] = dp[i - len] + 1;
                    }
                }
            }
        }
    }
    return dp[n];
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int K;
        scanf("%d", &K);
        char words[K][MAX_LEN];
        for (int i = 0; i < K; i++) {
            scanf("%s", words[i]);
        }
        int digitMap[MAX_DIGITS][15];
        for (int i = 0; i < MAX_DIGITS; i++) {
            int m;
            scanf("%d", &m);
            for (int j = 0; j < m; j++) {
                scanf(" %c", &digitMap[i][j]);
            }
        }
        int n;
        scanf("%d", &n);
        int digits[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &digits[i]);
        }
        int result = minWords(words, K, digitMap, n, digits);
        printf("Case %d: %d\n", t + 1, result);
    }
    return 0;
}

