#include <vector>
using namespace std;
#define MAX 10000
#define MAX_LEN 20
#define MAX_DIGITS 10

int minWords(vector<string> words, int K, vector<vector<char>> digitMap, int n, vector<int> digits) {
    vector<int> dp(n + 1, -1);
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < K; j++) {
            int len = words[j].length();
            if (i >= len) {
                bool match = true;
                for (int k = 0; k < len; k++) {
                    if (find(digitMap[digits[i - k - 1]].begin(), digitMap[digits[i - k - 1]].end(), words[j][len - k - 1]) == digitMap[digits[i - k - 1]].end()) {
                        match = false;
                        break;
                    }
                }
                if (match && dp[i - len] != -1) {
                    if (dp[i] == -1 || dp[i - len] + 1 < dp[i]) {
                        dp[i] = dp[i - len] + 1;
                    }
                }
            }
        }
    }
    return dp[n];
}

