    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int K;
        cin >> K;
        vector<string> words(K);
        for (int i = 0; i < K; i++) {
            cin >> words[i];
        }
        vector<vector<char>> digitMap(MAX_DIGITS);
        for (int i = 0; i < MAX_DIGITS; i++) {
